  await page.screenshot({ path: path.join(outDir, '09-wall-off-plan-block-warning.png'), fullPage: false });

  fs.writeFileSync(path.join(outDir, 'summary.json'), JSON.stringify(summary, null, 2));
  await browser.close();
  console.log(`Wrote screenshots + summary to ${outDir}`);
})();
