      return {
        shell: s ? { top: s.top, bottom: s.bottom, height: s.height } : null,
        primary: p ? { top: p.top, bottom: p.bottom, height: p.height } : null,
        header: h ? { top: h.top, bottom: h.bottom, height: h.height } : null,
        footer: f ? { top: f.top, bottom: f.bottom, height: f.height } : null,
      };
    });
  }

  fs.writeFileSync(
    path.join(outDir, 'fullheight-summary.json'),
    JSON.stringify({ captures, metrics }, null, 2),
  );
  await browser.close();
  console.log('Wrote full-height captures and summary');
})();
